From 2b8200f7d701ea6ff9638f629f0bd81d2e48410c Mon Sep 17 00:00:00 2001
From: Dominik Stadler <centic@apache.org>
Date: Fri, 28 Dec 2018 19:53:03 +0000
Subject: [PATCH] Bug 61532: Fix setting values/types during formula evaluation
 for SXSSF

git-svn-id: https://svn.apache.org/repos/asf/poi/trunk@1849880 13f79535-47bb-0310-9956-ffa450edef68

diff --git a/src/ooxml/java/org/apache/poi/xssf/streaming/SheetDataWriter.java b/src/ooxml/java/org/apache/poi/xssf/streaming/SheetDataWriter.java
index ab97288d04..30a9c4ec62 100644
--- a/src/ooxml/java/org/apache/poi/xssf/streaming/SheetDataWriter.java
+++ b/src/ooxml/java/org/apache/poi/xssf/streaming/SheetDataWriter.java
@@ -262,6 +262,20 @@ public class SheetDataWriter implements Closeable {
                 break;
             }
             case FORMULA: {
+                switch(cell.getCachedFormulaResultType()) {
+                    case NUMERIC:
+                        writeAttribute("t", "n");
+                        break;
+                    case STRING:
+                        writeAttribute("t", STCellType.S.toString());
+                        break;
+                    case BOOLEAN:
+                        writeAttribute("t", "b");
+                        break;
+                    case ERROR:
+                        writeAttribute("t", "e");
+                        break;
+                }
                 _out.write("><f>");
                 outputQuotedString(cell.getCellFormula());
                 _out.write("</f>");
@@ -274,8 +288,27 @@ public class SheetDataWriter implements Closeable {
                             _out.write("</v>");
                         }
                         break;
-                    default:
+                    case STRING:
+                        String value = cell.getStringCellValue();
+                        if(value != null && !value.isEmpty()) {
+                            _out.write("<v>");
+                            _out.write(value);
+                            _out.write("</v>");
+                        }
+                        break;
+                    case BOOLEAN:
+                        _out.write("><v>");
+                        _out.write(cell.getBooleanCellValue() ? "1" : "0");
+                        _out.write("</v>");
                         break;
+                    case ERROR: {
+                        FormulaError error = FormulaError.forInt(cell.getErrorCellValue());
+
+                        _out.write("><v>");
+                        _out.write(error.getString());
+                        _out.write("</v>");
+                        break;
+                    }
                 }
                 break;
             }

diff --git a/src/ooxml/java/org/apache/poi/xssf/streaming/SXSSFCell.java b/src/ooxml/java/org/apache/poi/xssf/streaming/SXSSFCell.java
